3	// FIXME(kate-osborn): Dynamically calculate upstream zone size based on the number of upstreams.
4	// 512k will support up to 648 http upstream servers for OSS.
5	// NGINX Plus needs 1m to support roughly the same amount of http servers (556 upstream servers).
6	// For stream upstream servers, 512k will support 576 in OSS and 1m will support 991 in NGINX Plus
7	// https://github.com/nginx/nginx-gateway-fabric/issues/483
8	//
9	// if the keepalive directive is present, it is necessary to activate the load balancing method before the directive.
10	const upstreamsTemplateText = `
11	{{ range $u := . }}
12	upstream {{ $u.Name }} {
13	    {{ if $u.LoadBalancingMethod -}}
14	    {{ $u.LoadBalancingMethod }};
15	    {{- end }}
16	    {{ if $u.ZoneSize -}}
17	    zone {{ $u.Name }} {{ $u.ZoneSize }};
18	    {{ end -}}
19	
20	    {{ if $u.SessionPersistence.Name -}}
21	    sticky {{ $u.SessionPersistence.SessionType }} {{ $u.SessionPersistence.Name }}
22	    {{- if $u.SessionPersistence.Expiry }} expires={{ $u.SessionPersistence.Expiry }}{{- end }}
23	    {{- if $u.SessionPersistence.Path }} path={{ $u.SessionPersistence.Path }}{{- end }};
24	    {{ end -}}
25	
26	    {{- if $u.StateFile }}
27	    state {{ $u.StateFile }};
28	    {{- else }}
29	        {{ range $server := $u.Servers }}
30	    server {{ $server.Address }}{{ if $server.Resolve }} resolve{{ end }};
31	        {{- end }}
32	    {{- end }}
33	    {{ if $u.KeepAlive.Connections -}}
34	    keepalive {{ $u.KeepAlive.Connections }};
35	    {{- end }}
36	    {{ if $u.KeepAlive.Requests -}}
37	    keepalive_requests {{ $u.KeepAlive.Requests }};
38	    {{- end }}
39	    {{ if $u.KeepAlive.Time -}}
40	    keepalive_time {{ $u.KeepAlive.Time }};
41	    {{- end }}
42	    {{ if $u.KeepAlive.Timeout -}}
43	    keepalive_timeout {{ $u.KeepAlive.Timeout }};
44	    {{- end }}
45	}
46	{{ end -}}
47	`
