49	const streamUpstreamsTemplateText = `
50	{{ range $u := . }}
51	upstream {{ $u.Name }} {
52	    random two least_conn;
53	    {{ if $u.ZoneSize -}}
54	    zone {{ $u.Name }} {{ $u.ZoneSize }};
55	    {{- end }}
