18	{{- end }}
19	{{ end -}}
20	
21	# Set $gw_api_compliant_host variable to the value of $http_host unless $http_host is empty, then set it to the value
22	# of $host. We prefer $http_host because it contains the original value of the host header, which is required by the
23	# Gateway API. However, in an HTTP/1.0 request, it's possible that $http_host can be empty. In this case, we will use
24	# the value of $host. See http://nginx.org/en/docs/http/ngx_http_core_module.html#var_host.
25	map $http_host $gw_api_compliant_host {
26	    '' $host;
27	    default $http_host;
28	}
29	
30	# Understanding the Connection header behavior:
31	# For normal HTTP proxying with keepAlive disabled, we set Connection header to close. This tells the upstream to close the connection after the response.
32	# When upgrading the connection to WebSocket, we set Connection header to upgrade to inform the upstream to switch protocols.
33	# For normal HTTP proxying with keepAlive enabled, we leave the Connection header empty. This allows NGINX to manage persistent connections with the upstream.
34	
35	# Set $connection_header variable to upgrade when the $http_upgrade header is set, otherwise, set it to close. This
36	# allows support for websocket connections. See https://nginx.org/en/docs/http/websocket.html.
37	map $http_upgrade $connection_upgrade {
38	    default upgrade;
39	    '' close;
40	}
41	
42	# Set $connection_keepalive variable to upgrade when the $http_upgrade header is set, otherwise, set it to empty for when
43	# keepAlive is enabled.
44	map $http_upgrade $connection_keepalive {
45	    default upgrade;
46	    '' '';
47	}
